import{_ as s,o as l,c as a,ai as e}from"./chunks/framework.CaiDwmc7.js";const u=JSON.parse('{"title":"第二阶段：MVP Server / 数据中台规划【让模型吃到“干净数据”】","description":"","frontmatter":{},"headers":[],"relativePath":"tech-system/ai/mvp-server.md","filePath":"tech-system/ai/mvp-server.md"}'),n={name:"tech-system/ai/mvp-server.md"};function t(r,i,o,h,p,k){return l(),a("div",null,[...i[0]||(i[0]=[e(`<h1 id="第二阶段-mvp-server-数据中台规划【让模型吃到-干净数据-】" tabindex="-1">第二阶段：MVP Server / 数据中台规划【让模型吃到“干净数据”】 <a class="header-anchor" href="#第二阶段-mvp-server-数据中台规划【让模型吃到-干净数据-】" aria-label="Permalink to “第二阶段：MVP Server / 数据中台规划【让模型吃到“干净数据”】”">​</a></h1><blockquote><p>这一篇主要回答：<strong>当你不满足于“让模型自己乱搜”，想让它基于你整理好的数据来分析/回答时，应该怎么规划一个简单的数据中台？</strong></p></blockquote><hr><h2 id="_1-不同学习目的下-这一阶段的价值" tabindex="-1">1. 不同学习目的下，这一阶段的价值 <a class="header-anchor" href="#_1-不同学习目的下-这一阶段的价值" aria-label="Permalink to “1. 不同学习目的下，这一阶段的价值”">​</a></h2><ul><li><p><strong>目的 A：只是想提升个人效率</strong></p><ul><li>这阶段可以<strong>先不深入</strong>，知道有这么一层就够了。</li><li>你可以使用现成的知识库工具（比如一些托管的 RAG 平台）。</li></ul></li><li><p><strong>目的 B：想做自己的小产品 / 服务</strong></p><ul><li>这是一个非常关键的阶段：你需要一个“中间层”来整理数据，给模型用。</li><li>输出物：一个简单的 HTTP 服务，能把<strong>你关心的数据统一清洗好</strong>，以 JSON 形式提供给 LLM/Agent。</li></ul></li><li><p><strong>目的 C：考虑走 AI 平台 / 后端工程方向</strong></p><ul><li>这阶段是你的主战场：API 设计、数据清洗、任务调度，都是后续扩展的基础。</li></ul></li></ul><p>对你目前来说，如果以后希望做一点和 “投资 / 面试 / 学习助手” 相关的小产品，<strong>建议认真走完这一阶段</strong>。</p><hr><h2 id="_2-mvp-server-的核心思路" tabindex="-1">2. MVP Server 的核心思路 <a class="header-anchor" href="#_2-mvp-server-的核心思路" aria-label="Permalink to “2. MVP Server 的核心思路”">​</a></h2><p>一句话概括：<br><strong>“把外部世界（新闻、行情、数据库、文档）的复杂数据，变成一个模型容易吃的统一接口。”</strong></p><p>核心关注三件事：</p><ol><li><strong>数据从哪来</strong>：HTTP API、数据库、爬虫、本地文件等。</li><li><strong>数据长什么样</strong>：不同源格式统一、字段命名清晰。</li><li><strong>对外怎么提供</strong>：简单、稳定的 REST 接口（甚至只有 2～3 个核心接口）。</li></ol><hr><h2 id="_3-建议的实现路线-按一两周规划" tabindex="-1">3. 建议的实现路线（按一两周规划） <a class="header-anchor" href="#_3-建议的实现路线-按一两周规划" aria-label="Permalink to “3. 建议的实现路线（按一两周规划）”">​</a></h2><h3 id="第一步-选技术栈-拉一个最小服务骨架-1-2-天" tabindex="-1">第一步：选技术栈 + 拉一个最小服务骨架（1～2 天） <a class="header-anchor" href="#第一步-选技术栈-拉一个最小服务骨架-1-2-天" aria-label="Permalink to “第一步：选技术栈 + 拉一个最小服务骨架（1～2 天）”">​</a></h3><ul><li>技术栈可以选你熟悉的： <ul><li>Java + Spring Boot</li><li>Node.js + Express/Nest</li><li>Python + FastAPI/Flask</li></ul></li><li>搭一个最小骨架： <ul><li>一个健康检查接口：<code>/health</code> → 返回 <code>ok</code></li><li>一个简单的“测试数据”接口：<code>/demo</code> → 返回一段固定 JSON。</li></ul></li></ul><blockquote><p>这一步主要是确认：<strong>你能很轻松地在本地启动 / 调试 / 改动一个服务项目</strong>。</p></blockquote><h3 id="第二步-接-1-2-个外部数据源-2-4-天" tabindex="-1">第二步：接 1～2 个外部数据源（2～4 天） <a class="header-anchor" href="#第二步-接-1-2-个外部数据源-2-4-天" aria-label="Permalink to “第二步：接 1～2 个外部数据源（2～4 天）”">​</a></h3><p>结合你的兴趣，可以选：</p><ul><li>新闻/公告接口</li><li>股票/基金/数字货币行情接口</li><li>或者任何你喜欢的公开 API（天气、汇率等）</li></ul><p>实现步骤：</p><ol><li>写代码调用外部 API，拿到原始 JSON。</li><li>根据你想给 LLM 用的场景，设计一个统一结构，例如：<div class="language-json line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">json</span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">{</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">  &quot;symbol&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;XYZ&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">,</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">  &quot;time&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;2026-03-10T10:00:00Z&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">,</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">  &quot;source&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;news_api&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">,</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">  &quot;title&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;标题&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">,</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">  &quot;content&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;正文摘要&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">,</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">  &quot;tags&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: [</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;利好&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">, </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;财报&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">]</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">}</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br><span class="line-number">6</span><br><span class="line-number">7</span><br><span class="line-number">8</span><br></div></div></li><li>对外暴露接口： <ul><li>例如：<code>GET /ai/context?symbol=XYZ&amp;limit=20</code></li><li>返回最近若干条相关新闻/数据。</li></ul></li></ol><h3 id="第三步-和-llm-agent-串起来-2-3-天" tabindex="-1">第三步：和 LLM / Agent 串起来（2～3 天） <a class="header-anchor" href="#第三步-和-llm-agent-串起来-2-3-天" aria-label="Permalink to “第三步：和 LLM / Agent 串起来（2～3 天）”">​</a></h3><ul><li>在你的 Agent 或简单脚本中： <ol><li>先调用 <code>MVP Server</code> 获取结构化数据。</li><li>把这些数据整理成 Prompt 的一部分。</li><li>再调用 LLM 生成分析/解释。</li></ol></li></ul><blockquote><p>这一步做完，你就有了一个<strong>“自己的数据 → 自己的中台 → LLM 分析”</strong>的闭环，与直接让模型乱抓网络数据相比，更可控、更稳定。</p></blockquote><hr><h2 id="_4-结合你当前的学习内容-可以做的-1-个典型项目" tabindex="-1">4. 结合你当前的学习内容：可以做的 1 个典型项目 <a class="header-anchor" href="#_4-结合你当前的学习内容-可以做的-1-个典型项目" aria-label="Permalink to “4. 结合你当前的学习内容：可以做的 1 个典型项目”">​</a></h2><p><strong>项目：面向“投资/学习”的 AI 中台（简版）</strong></p><ul><li>数据源示例： <ul><li>你的 Java 面试文档库（可选，后续接 RAG 再用）。</li><li>新闻/行情接口（例如选择 1～2 个你关注的标的）。</li></ul></li><li>MVP Server 提供的接口（示例）： <ul><li><code>/ai/context/stock?symbol=XXX</code></li><li><code>/ai/context/news?keyword=java面试</code></li></ul></li><li>二次消费： <ul><li>你的 Agent / 小工具调用这些接口，再调用 LLM 做： <ul><li>投资说明书 → 用通俗语言解释。</li><li>面试热点 → 从最近新闻中提取技术关键词，变成面试问题。</li></ul></li></ul></li></ul><blockquote><p>这样你练习 MVP Server 的同时，也是在围绕自己主线（<strong>远程工作 + 投资/学习场景</strong>）打磨实际工程能力。</p></blockquote><hr><h2 id="_5-这一阶段的-合格线" tabindex="-1">5. 这一阶段的“合格线” <a class="header-anchor" href="#_5-这一阶段的-合格线" aria-label="Permalink to “5. 这一阶段的“合格线””">​</a></h2><p>可以把“做完”定义为：</p><ul><li>至少有一个独立的服务项目： <ul><li>能跑起来。</li><li>提供 1～3 个稳定 REST 接口。</li><li>能从真实外部数据源拿数据、清洗、统一输出格式。</li></ul></li><li>你的某个 LLM/Agent 脚本已经开始<strong>依赖这个服务</strong>，而不是直接打外部 API。</li></ul><p>做到这一步，你已经比大部分只会“纯聊天”用 AI 的人，<strong>多出一整层“工程能力”</strong>。</p>`,34)])])}const c=s(n,[["render",t]]);export{u as __pageData,c as default};
